+    fn handle_log_pane_key(&self, code: ftui::KeyCode) -> bool {
+        use ftui::KeyCode;
+        let mut pane = lock_mutex(&self.log_pane);
+        match code {
+            // Scrolling
+            KeyCode::Up => {
+                pane.scroll_up(1);
+                true
+            }
+            KeyCode::Down => {
+                pane.scroll_down(1);
+                true
+            }
+            KeyCode::PageUp => {
+                pane.page_up();
+                true
+            }
+            KeyCode::PageDown => {
+                pane.page_down();
+                true
+            }
+            KeyCode::Home => {
+                pane.scroll_to_top();
+                true
+            }
+            KeyCode::End => {
+                pane.scroll_to_bottom();
+                true
+            }
+            // Follow mode toggle
+            KeyCode::Char('f') => {
+                pane.toggle_follow();
+                true
+            }
+            // Search navigation
+            KeyCode::Char('n') => {
+                pane.next_match();
+                true
+            }
+            KeyCode::Char('N') => {
+                pane.prev_match();
+                true
+            }
+            // Clear search
+            KeyCode::Escape => {
+                pane.clear_search();
+                true
+            }
+            _ => false,
+        }
+    }
