+    fn buffer_text(f: &ftui::Frame<'_>) -> String {
+        let mut t = String::new();
+        for y in 0..f.buffer.height() {
+            for x in 0..f.buffer.width() {
+                if let Some(c) = f.buffer.get(x, y) {
+                    if let Some(ch) = c.content.as_char() {
+                        t.push(ch);
+                    } else if !c.is_continuation() {
+                        t.push(' ');
+                    }
+                }
+            }
+            t.push('\n');
+        }
+        t
+    }
